 1	import React, { ReactNode } from 'react';
 2	import { Trans } from 'react-i18next';
 3	import { useNavigate, useParams } from 'react-router-dom-v5-compat';
 4	
 5	import { K8sResourceCommon, ListPageHeader } from '@openshift-console/dynamic-plugin-sdk';
 6	import {
 7	  Button,
 8	  ButtonVariant,
 9	  EmptyState,
10	  EmptyStateActions,
11	  EmptyStateBody,
12	  EmptyStateFooter,
13	  EmptyStateHeader,
14	  EmptyStateIcon,
15	} from '@patternfly/react-core';
16	import { AddCircleOIcon } from '@patternfly/react-icons';
17	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
18	import { isEmpty } from '@utils/utils';
19	
20	import ExternalLink from '../ExternalLink/ExternalLink';
21	import Loading from '../Loading/Loading';
22	
23	type ListEmptyStateProps<T> = {
24	  children: ReactNode;
25	  createButtonlink: string;
26	  data: T[];
27	  kind: string;
28	  learnMoreLink: string;
29	  loaded: boolean;
30	  title: string;
31	};
32	
33	const ListEmptyState = <T extends K8sResourceCommon>({
34	  children,
35	  createButtonlink,
36	  data,
37	  kind,
38	  learnMoreLink,
39	  loaded,
40	  title,
41	}: ListEmptyStateProps<T>) => {
42	  const { t } = useNetworkingTranslation();
43	  const navigate = useNavigate();
44	  const params = useParams();
45	  if (!loaded) return <Loading />;
46	
47	  if (isEmpty(data))
48	    return (
49	      <>
50	        <ListPageHeader title={title} />
51	        <EmptyState>
52	          <EmptyStateHeader
53	            headingLevel="h4"
54	            icon={<EmptyStateIcon icon={AddCircleOIcon} />}
55	            titleText={t('No {{kind}} found', { kind })}
56	          />
57	          <EmptyStateBody>
58	            <Trans t={t}>
59	              Click <b>Create {{ kind }}</b> to create your first {{ kind }}
60	            </Trans>
61	          </EmptyStateBody>
62	          <EmptyStateFooter>
63	            <EmptyStateActions>
64	              <Button
65	                onClick={() =>
66	                  navigate(
67	                    params?.ns
68	                      ? createButtonlink
69	                      : `/k8s/ns/default/${params.plural}/${createButtonlink}`,
70	                  )
71	                }
72	                variant={ButtonVariant.primary}
73	              >
74	                {t('Create {{ kind }}', { kind })}
75	              </Button>
76	            </EmptyStateActions>
77	            <EmptyStateActions>
78	              <ExternalLink href={learnMoreLink}>
79	                {t('Learn more about {{ kind }}', { kind })}
80	              </ExternalLink>
81	            </EmptyStateActions>
82	          </EmptyStateFooter>
83	        </EmptyState>
84	      </>
85	    );
86	
87	  return <>{children}</>;
88	};
89	
90	export default ListEmptyState;

